// ═══════════════════════════════════════════════════════════════════════════════
// ADMIN SISWA DELETE FUNCTIONS
// Fungsi untuk menghapus siswa per kelas dan semua siswa (menggunakan Supabase)
// ═══════════════════════════════════════════════════════════════════════════════

function escSiswaDelete(value) {
  return String(value == null ? '' : value).replace(/[&<>"']/g, c => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;'
  }[c]));
}

async function selectPesertaSiswaDelete(filters = {}, columns = '*') {
  if (typeof window.fetchSupabase === 'function') {
    const res = await window.fetchSupabase('peserta', filters);
    if (!res || !res.success) throw new Error((res && (res.error || res.message)) || 'Gagal memuat peserta');
    return res.data || [];
  }
  if (window.supabase && typeof window.supabase.from === 'function') {
    let query = window.supabase.from('peserta').select(columns);
    Object.entries(filters || {}).forEach(([key, val]) => {
      if (typeof val === 'string' && val.startsWith('eq.')) query = query.eq(key, val.slice(3));
    });
    const { data, error } = await query;
    if (error) throw error;
    return data || [];
  }
  if (window.db && typeof window.db.ref === 'function') {
    const snap = await window.db.ref('/peserta').once('value');
    let list = Object.entries(snap.val() || {}).map(([id, row]) => ({ id, ...(row || {}) }));
    Object.entries(filters || {}).forEach(([key, val]) => {
      if (typeof val === 'string' && val.startsWith('eq.')) list = list.filter(row => String(row[key] || '') === val.slice(3));
    });
    return list;
  }
  throw new Error('Koneksi database belum siap');
}

async function deletePesertaSiswaDelete(id) {
  if (typeof window.deleteSupabase === 'function') {
    const res = await window.deleteSupabase('peserta', { id: 'eq.' + id });
    if (!res || !res.success) throw new Error((res && (res.error || res.message)) || 'Gagal menghapus peserta');
    return true;
  }
  if (window.supabase && typeof window.supabase.from === 'function') {
    const { error } = await window.supabase.from('peserta').delete().eq('id', id);
    if (error) throw error;
    return true;
  }
  if (window.db && typeof window.db.ref === 'function') {
    await window.db.ref('/peserta/' + id).remove();
    return true;
  }
  throw new Error('Koneksi database belum siap');
}

/**
 * Tampilkan preview siswa yang akan dihapus per kelas
 */
window.showDeleteKelasPreview = async function() {
  const kelasSelect = document.getElementById('filter-kelas-delete');
  if (!kelasSelect) {
    showCustomAlert('Error', 'Elemen filter kelas tidak ditemukan.', '❌');
    return;
  }

  const selectedKelas = kelasSelect.value;
  if (!selectedKelas || selectedKelas === '') {
    showCustomAlert('Pilih Kelas', 'Silakan pilih kelas terlebih dahulu.', '⚠️');
    return;
  }

  showLoading('Memuat data siswa...');
  try {
    // Ambil semua siswa dari runtime database yang tersedia
    const pesertaData = await selectPesertaSiswaDelete({ kelas: 'eq.' + selectedKelas });

    if (!pesertaData || pesertaData.length === 0) {
      showCustomAlert('Tidak Ada Data', `Tidak ada siswa di kelas "${selectedKelas}".`, 'ℹ️');
      return;
    }

    // Format data untuk modal
    const siswaList = pesertaData.map(siswa => ({
      id: siswa.id,
      nama: siswa.nama,
      kelas: siswa.kelas
    }));

    // Buka modal preview
    showDeleteKelasModal(selectedKelas, siswaList);
  } catch (error) {
    console.error('Error loading siswa:', error);
    showCustomAlert('Gagal', `Gagal memuat data siswa: ${error.message}`, '❌');
  } finally {
    hideLoading();
  }
};

/**
 * Tampilkan modal preview penghapusan per kelas
 */
window.showDeleteKelasModal = function(kelas, siswaList) {
  const overlay = document.createElement('div');
  overlay.id = 'delete-kelas-overlay';
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(15, 23, 42, 0.55);
    backdrop-filter: blur(4px);
    z-index: 9000;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 20px;
  `;

  const modal = document.createElement('div');
  modal.style.cssText = `
    background: #fff;
    border-radius: 16px;
    padding: 28px;
    width: 100%;
    max-width: 600px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
    max-height: 80vh;
    overflow-y: auto;
  `;

  const siswaListHTML = siswaList
    .map((siswa, idx) => `
      <div style="display: flex; align-items: center; padding: 12px; border-bottom: 1px solid #e5e7eb; background: ${idx % 2 === 0 ? '#f9fafb' : '#fff'};">
        <div style="width: 32px; height: 32px; border-radius: 50%; background: #dbeafe; color: #2563eb; display: flex; align-items: center; justify-content: center; font-weight: 700; margin-right: 12px; flex-shrink: 0;">
          ${escSiswaDelete(siswa.nama || '?').charAt(0).toUpperCase()}
        </div>
        <div style="flex: 1;">
          <div style="font-weight: 600; color: #1e293b;">${escSiswaDelete(siswa.nama)}</div>
          <div style="font-size: 0.75rem; color: #64748b;">ID: ${escSiswaDelete(siswa.id)}</div>
        </div>
      </div>
    `)
    .join('');

  modal.innerHTML = `
    <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 20px;">
      <h3 style="margin: 0; font-size: 1.1rem; font-weight: 800; color: #1e293b;">
        🗑️ Hapus Siswa Kelas "${kelas}"
      </h3>
      <button onclick="closeDeleteKelasModal()" style="background: none; border: none; cursor: pointer; font-size: 1.3rem; color: #94a3b8; line-height: 1;">✕</button>
    </div>

    <div style="background: #fef2f2; border: 1px solid #fecaca; border-radius: 10px; padding: 14px; margin-bottom: 16px; display: flex; gap: 10px; align-items: flex-start;">
      <div style="font-size: 1.2rem; flex-shrink: 0;">⚠️</div>
      <div>
        <div style="font-weight: 700; color: #b91c1c; margin-bottom: 4px;">Peringatan!</div>
        <div style="font-size: 0.85rem; color: #7f1d1d;">
          Anda akan menghapus <strong>${siswaList.length} siswa</strong> dari kelas <strong>"${kelas}"</strong>. Tindakan ini TIDAK DAPAT DIBATALKAN!
        </div>
      </div>
    </div>

    <div style="margin-bottom: 16px;">
      <div style="font-size: 0.8rem; font-weight: 700; color: #64748b; margin-bottom: 10px;">
        DAFTAR SISWA YANG AKAN DIHAPUS (${siswaList.length}):
      </div>
      <div style="border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden; max-height: 300px; overflow-y: auto;">
        ${siswaListHTML}
      </div>
    </div>

    <div style="display: flex; gap: 10px; margin-top: 20px;">
      <button onclick="closeDeleteKelasModal()" style="flex: 1; padding: 12px; border-radius: 10px; border: 1.5px solid #e2e8f0; background: #f8fafc; color: #64748b; font-weight: 700; cursor: pointer; font-size: 0.9rem;">
        Batal
      </button>
      <button onclick="confirmDeleteKelas('${kelas}', ${siswaList.length})" style="flex: 1; padding: 12px; border-radius: 10px; border: none; background: linear-gradient(135deg, #dc2626, #b91c1c); color: #fff; font-weight: 800; cursor: pointer; font-size: 0.9rem; display: flex; align-items: center; justify-content: center; gap: 8px;">
        <svg width="16" height="16" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
        Hapus ${siswaList.length} Siswa
      </button>
    </div>
  `;

  overlay.appendChild(modal);
  document.body.appendChild(overlay);

  // Animate
  setTimeout(() => {
    overlay.style.opacity = '1';
    modal.style.opacity = '1';
    modal.style.transform = 'translate(-50%, -50%) scale(1)';
  }, 10);
};

/**
 * Tutup modal preview penghapusan per kelas
 */
window.closeDeleteKelasModal = function() {
  const overlay = document.getElementById('delete-kelas-overlay');
  if (overlay) {
    overlay.style.opacity = '0';
    setTimeout(() => {
      overlay.remove();
    }, 300);
  }
};

/**
 * Konfirmasi final penghapusan per kelas
 */
window.confirmDeleteKelas = async function(kelas, count) {
  const confirmText = prompt(
    `Ketik nama kelas "${kelas}" untuk mengkonfirmasi penghapusan ${count} siswa:`,
    ''
  );

  if (confirmText !== kelas) {
    showCustomAlert('Dibatalkan', 'Penghapusan dibatalkan.', '❌');
    closeDeleteKelasModal();
    return;
  }

  closeDeleteKelasModal();
  showLoading('Menghapus siswa per kelas...');

  try {
    // Ambil semua siswa dari runtime database yang tersedia
    const pesertaData = await selectPesertaSiswaDelete({ kelas: 'eq.' + kelas }, 'id');

    if (!pesertaData || pesertaData.length === 0) {
      showCustomAlert('Tidak Ada Data', `Tidak ada siswa di kelas "${kelas}".`, 'ℹ️');
      return;
    }

    // Hapus siswa satu per satu
    let deletedCount = 0;
    for (const siswa of pesertaData) {
      try {
        await deletePesertaSiswaDelete(siswa.id);
        deletedCount++;
      } catch (err) {
        console.error(`Gagal menghapus siswa ${siswa.id}:`, err);
      }
    }

    // Refresh UI
    loadAdminSiswa();
    updateFilterKelasDelete();

    showCustomAlert(
      'Berhasil',
      `${deletedCount} siswa dari kelas "${kelas}" telah dihapus.`,
      '✅'
    );
  } catch (error) {
    console.error('Error deleting siswa per kelas:', error);
    showCustomAlert('Gagal', `Gagal menghapus siswa: ${error.message}`, '❌');
  } finally {
    hideLoading();
  }
};

/**
 * Hapus semua siswa dalam satu kelas (dipanggil dari tombol)
 */
window.deleteSiswaPerKelas = function() {
  window.showDeleteKelasPreview();
};

/**
 * Tampilkan preview semua siswa yang akan dihapus
 */
window.showDeleteSemuaPreview = async function() {
  showLoading('Memuat data siswa...');
  try {
    // Ambil semua siswa dari runtime database yang tersedia
    const pesertaData = await selectPesertaSiswaDelete();

    if (!pesertaData || pesertaData.length === 0) {
      showCustomAlert('Tidak Ada Data', 'Tidak ada siswa untuk dihapus.', 'ℹ️');
      return;
    }

    // Format data untuk modal
    const siswaList = pesertaData.map(siswa => ({
      id: siswa.id,
      nama: siswa.nama,
      kelas: siswa.kelas
    }));

    // Buka modal preview
    showDeleteSemuaModal(siswaList);
  } catch (error) {
    console.error('Error loading siswa:', error);
    showCustomAlert('Gagal', `Gagal memuat data siswa: ${error.message}`, '❌');
  } finally {
    hideLoading();
  }
};

/**
 * Tampilkan modal preview penghapusan semua siswa
 */
window.showDeleteSemuaModal = function(siswaList) {
  const overlay = document.createElement('div');
  overlay.id = 'delete-semua-overlay';
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(15, 23, 42, 0.55);
    backdrop-filter: blur(4px);
    z-index: 9000;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 20px;
  `;

  const modal = document.createElement('div');
  modal.style.cssText = `
    background: #fff;
    border-radius: 16px;
    padding: 28px;
    width: 100%;
    max-width: 700px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
    max-height: 80vh;
    overflow-y: auto;
  `;

  // Group siswa by kelas
  const byKelas = {};
  siswaList.forEach(siswa => {
    if (!byKelas[siswa.kelas]) {
      byKelas[siswa.kelas] = [];
    }
    byKelas[siswa.kelas].push(siswa);
  });

  const kelasListHTML = Object.entries(byKelas)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([kelas, siswaKelas]) => `
      <div style="margin-bottom: 16px; border: 1px solid #e5e7eb; border-radius: 10px; overflow: hidden;">
        <div style="background: #f1f5f9; padding: 12px 16px; font-weight: 700; color: #1e293b; border-bottom: 1px solid #e5e7eb;">
          📚 ${kelas} (${siswaKelas.length} siswa)
        </div>
        <div style="max-height: 200px; overflow-y: auto;">
          ${siswaKelas
            .map((siswa, idx) => `
              <div style="display: flex; align-items: center; padding: 10px 16px; border-bottom: 1px solid #e5e7eb; background: ${idx % 2 === 0 ? '#f9fafb' : '#fff'};">
                <div style="width: 28px; height: 28px; border-radius: 50%; background: #dbeafe; color: #2563eb; display: flex; align-items: center; justify-content: center; font-weight: 700; margin-right: 10px; flex-shrink: 0; font-size: 0.8rem;">
                  ${escSiswaDelete(siswa.nama || '?').charAt(0).toUpperCase()}
                </div>
                <div style="flex: 1;">
                  <div style="font-weight: 600; color: #1e293b; font-size: 0.9rem;">${escSiswaDelete(siswa.nama)}</div>
                  <div style="font-size: 0.7rem; color: #64748b;">ID: ${escSiswaDelete(siswa.id)}</div>
                </div>
              </div>
            `)
            .join('')}
        </div>
      </div>
    `)
    .join('');

  modal.innerHTML = `
    <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 20px;">
      <h3 style="margin: 0; font-size: 1.1rem; font-weight: 800; color: #1e293b;">
        🗑️ Hapus SEMUA Siswa
      </h3>
      <button onclick="closeDeleteSemuaModal()" style="background: none; border: none; cursor: pointer; font-size: 1.3rem; color: #94a3b8; line-height: 1;">✕</button>
    </div>

    <div style="background: #fef2f2; border: 1px solid #fecaca; border-radius: 10px; padding: 14px; margin-bottom: 16px; display: flex; gap: 10px; align-items: flex-start;">
      <div style="font-size: 1.3rem; flex-shrink: 0;">🚨</div>
      <div>
        <div style="font-weight: 700; color: #b91c1c; margin-bottom: 4px;">PERINGATAN KRITIS!</div>
        <div style="font-size: 0.85rem; color: #7f1d1d;">
          Anda akan menghapus <strong>SEMUA ${siswaList.length} siswa</strong> dari sistem. Tindakan ini TIDAK DAPAT DIBATALKAN dan akan menghapus semua data siswa secara permanen!
        </div>
      </div>
    </div>

    <div style="margin-bottom: 16px;">
      <div style="font-size: 0.8rem; font-weight: 700; color: #64748b; margin-bottom: 10px;">
        DAFTAR SISWA YANG AKAN DIHAPUS (${siswaList.length}):
      </div>
      <div style="max-height: 350px; overflow-y: auto;">
        ${kelasListHTML}
      </div>
    </div>

    <div style="display: flex; gap: 10px; margin-top: 20px;">
      <button onclick="closeDeleteSemuaModal()" style="flex: 1; padding: 12px; border-radius: 10px; border: 1.5px solid #e2e8f0; background: #f8fafc; color: #64748b; font-weight: 700; cursor: pointer; font-size: 0.9rem;">
        Batal
      </button>
      <button onclick="confirmDeleteSemua(${siswaList.length})" style="flex: 1; padding: 12px; border-radius: 10px; border: none; background: linear-gradient(135deg, #dc2626, #b91c1c); color: #fff; font-weight: 800; cursor: pointer; font-size: 0.9rem; display: flex; align-items: center; justify-content: center; gap: 8px;">
        <svg width="16" height="16" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
        Hapus ${siswaList.length} Siswa
      </button>
    </div>
  `;

  overlay.appendChild(modal);
  document.body.appendChild(overlay);

  // Animate
  setTimeout(() => {
    overlay.style.opacity = '1';
    modal.style.opacity = '1';
    modal.style.transform = 'translate(-50%, -50%) scale(1)';
  }, 10);
};

/**
 * Tutup modal preview penghapusan semua siswa
 */
window.closeDeleteSemuaModal = function() {
  const overlay = document.getElementById('delete-semua-overlay');
  if (overlay) {
    overlay.style.opacity = '0';
    setTimeout(() => {
      overlay.remove();
    }, 300);
  }
};

/**
 * Konfirmasi final penghapusan semua siswa
 */
window.confirmDeleteSemua = async function(count) {
  const confirmText = prompt(
    `Ketik "HAPUS SEMUA SISWA" untuk mengkonfirmasi penghapusan permanen ${count} siswa:`,
    ''
  );

  if (confirmText !== 'HAPUS SEMUA SISWA') {
    showCustomAlert('Dibatalkan', 'Penghapusan dibatalkan.', '❌');
    closeDeleteSemuaModal();
    return;
  }

  closeDeleteSemuaModal();
  showLoading('Menghapus semua siswa...');

  try {
    // Ambil semua siswa dari runtime database yang tersedia
    const pesertaData = await selectPesertaSiswaDelete({}, 'id');

    if (!pesertaData || pesertaData.length === 0) {
      showCustomAlert('Tidak Ada Data', 'Tidak ada siswa untuk dihapus.', 'ℹ️');
      return;
    }

    // Hapus semua siswa
    let deletedCount = 0;
    for (const siswa of pesertaData) {
      try {
        await deletePesertaSiswaDelete(siswa.id);
        deletedCount++;
      } catch (err) {
        console.error(`Gagal menghapus siswa ${siswa.id}:`, err);
      }
    }

    // Refresh UI
    loadAdminSiswa();
    updateFilterKelasDelete();

    showCustomAlert(
      'Berhasil',
      `${deletedCount} siswa telah dihapus dari sistem.`,
      '✅'
    );
  } catch (error) {
    console.error('Error deleting all siswa:', error);
    showCustomAlert('Gagal', `Gagal menghapus siswa: ${error.message}`, '❌');
  } finally {
    hideLoading();
  }
};

/**
 * Hapus SEMUA siswa di sistem (dipanggil dari tombol)
 */
window.deleteSiswaSemuanya = function() {
  window.showDeleteSemuaPreview();
};

/**
 * Update filter kelas dropdown setelah perubahan data
 */
window.updateFilterKelasDelete = async function() {
  const filterSelect = document.getElementById('filter-kelas-delete');
  if (!filterSelect) return;

  try {
    // Ambil daftar kelas unik dari runtime database yang tersedia
    const pesertaData = await selectPesertaSiswaDelete({}, 'kelas');

    // Ambil daftar kelas unik
    const kelasList = [...new Set(
      pesertaData.map(p => p.kelas).filter(Boolean)
    )].sort((a, b) => String(a).localeCompare(String(b), 'id-ID'));

    // Update dropdown
    filterSelect.innerHTML = '<option value="">Semua Kelas</option>' +
      kelasList.map(kelas => `<option value="${escSiswaDelete(kelas)}">${escSiswaDelete(kelas)}</option>`).join('');
  } catch (error) {
    console.error('Error updating filter kelas:', error);
  }
};

/**
 * Initialize filter kelas dropdown saat halaman siswa dimuat
 */
window.initFilterKelasDelete = async function() {
  const filterSelect = document.getElementById('filter-kelas-delete');
  if (!filterSelect) return;

  try {
    // Ambil daftar kelas unik dari runtime database yang tersedia
    const pesertaData = await selectPesertaSiswaDelete({}, 'kelas');

    // Ambil daftar kelas unik
    const kelasList = [...new Set(
      pesertaData.map(p => p.kelas).filter(Boolean)
    )].sort((a, b) => String(a).localeCompare(String(b), 'id-ID'));

    // Populate dropdown
    filterSelect.innerHTML = '<option value="">Semua Kelas</option>' +
      kelasList.map(kelas => `<option value="${escSiswaDelete(kelas)}">${escSiswaDelete(kelas)}</option>`).join('');
  } catch (error) {
    console.error('Error initializing filter kelas:', error);
  }
};

// Initialize saat tab siswa dibuka
document.addEventListener('DOMContentLoaded', function() {
  // Hook ke tab siswa
  const siswaTab = document.querySelector('[data-tab="tab-siswa"]');
  if (siswaTab) {
    siswaTab.addEventListener('click', function() {
      setTimeout(() => {
        initFilterKelasDelete();
      }, 100);
    });
  }
});
